[data-theme="light"] .leaderboard-table tr:hover td { background: #f6f8fa; }

/* ── Theme Toggle ────────────────────────────────────────────────────── */

.theme-toggle {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 6px 10px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 1rem;
  line-height: 1;
  transition: background 0.2s, border-color 0.2s;
}

.theme-toggle:hover {
  background: var(--bg-hover);
  border-color: var(--accent);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  min-height: 100vh;
}

/* ── Header ──────────────────────────────────────────────────────────── */

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 100;
}

.header-left {
  display: flex;
  align-items: baseline;
  gap: 12px;
}

.logo {
  font-size: 1.4rem;
  font-weight: 700;
  color: var(--text-primary);
}

.tagline {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--green);
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

/* ── Main ────────────────────────────────────────────────────────────── */

.main {
  max-width: 1200px;
  margin: 0 auto;
  padding: 24px;
}

/* ── Views ────────────────────────────────────────────────────────────── */

.view {
  display: none;
}

.view.active {
  display: block;
}

.view-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.view-header h2 {
  font-size: 1.3rem;
  font-weight: 600;
}

.view-actions {
  display: flex;
  gap: 8px;
}

/* ── Buttons ─────────────────────────────────────────────────────────── */

.btn {
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
}

.btn:hover {
  background: var(--bg-hover);
  border-color: var(--text-muted);
}

.btn-secondary {
  background: transparent;
}

#bookmarkFilterBtn.active {
  background: var(--accent);
  color: #000;
  border-color: var(--accent);
}

.bookmark-star {
  transition: transform 0.15s ease;
}
.bookmark-star:hover {
  transform: scale(1.3);
}

.btn-ghost {
  background: transparent;
  border: none;
  color: var(--accent);
  padding: 8px 12px;
}

.btn-ghost:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

.select-input {
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
}

/* ── Session List ────────────────────────────────────────────────────── */

.session-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.session-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px 20px;
  cursor: pointer;
  transition: all 0.15s ease;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.session-card:hover {
  border-color: var(--accent);
  background: var(--bg-tertiary);
}

.session-card-left {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.session-agent {
  font-weight: 600;
  font-size: 1rem;
}

.session-meta {
  font-size: 0.8rem;
  color: var(--text-secondary);
  display: flex;
  gap: 16px;
}

.session-card-right {
  display: flex;
  align-items: center;
  gap: 16px;
}

.session-tokens {
  text-align: right;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.session-tokens .count {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-primary);
}

.status-badge {
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.status-badge.active {
  background: var(--green-dim);
  color: var(--green);
}

.status-badge.completed {
  background: var(--purple-dim);
  color: var(--purple);
}

.status-badge.error {
  background: var(--red-dim);
  color: var(--red);
}

/* ── Session Info Bar ────────────────────────────────────────────────── */

.session-info-bar {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 12px;
  margin-bottom: 20px;
}

.info-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
}

.info-card .label {
  font-size: 0.75rem;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.info-card .value {
  font-size: 1.1rem;
  font-weight: 600;
}

/* ── Tabs ─────────────────────────────────────────────────────────────── */

.tabs {
  display: flex;
  gap: 2px;
  margin-bottom: 20px;
  border-bottom: 1px solid var(--border);
}

.tab {
  padding: 10px 20px;
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.15s ease;
}

.tab:hover {
  color: var(--text-primary);
}

.tab.active {
  color: var(--accent);
  border-bottom-color: var(--accent);
}

.tab-content {
  display: none;
}

.tab-content.active {
  display: block;
}

/* ── Timeline ─────────────────────────────────────────────────────────── */

.timeline {
  position: relative;
  padding-left: 32px;
}

.timeline::before {
  content: '';
  position: absolute;
  left: 12px;
  top: 0;
  bottom: 0;
  width: 2px;
  background: var(--border);
}

.timeline-event {
  position: relative;
  margin-bottom: 16px;
  padding: 14px 18px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  transition: all 0.15s ease;
}

.timeline-event:hover {
  border-color: var(--text-muted);
}

.timeline-event::before {
  content: '';
  position: absolute;
  left: -26px;
  top: 20px;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  border: 2px solid var(--border);
  background: var(--bg-primary);
}

.timeline-event.llm_call::before { background: var(--accent); border-color: var(--accent); }
.timeline-event.tool_call::before { background: var(--orange); border-color: var(--orange); }
.timeline-event.agent_call::before { background: var(--green); border-color: var(--green); }
.timeline-event.agent_error::before, .timeline-event.tool_error::before { background: var(--red); border-color: var(--red); }

.event-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.event-type {
  display: flex;
  align-items: center;
  gap: 8px;
}

.event-type-badge {
  padding: 3px 8px;
  border-radius: var(--radius-sm);
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
}

.event-type-badge.llm_call { background: rgba(88, 166, 255, 0.15); color: var(--accent); }
.event-type-badge.tool_call { background: var(--orange-dim); color: var(--orange); }
.event-type-badge.agent_call { background: var(--green-dim); color: var(--green); }
.event-type-badge.agent_error, .event-type-badge.tool_error { background: var(--red-dim); color: var(--red); }

.event-model {
  font-size: 0.8rem;
  color: var(--text-secondary);
  background: var(--bg-tertiary);
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.event-time {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.event-body {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.event-io {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-top: 8px;
}

.event-io-block {
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  font-family: 'SF Mono', Consolas, monospace;
  font-size: 0.8rem;
  color: var(--text-secondary);
  overflow: hidden;
  max-height: 120px;
  overflow-y: auto;
}

.event-io-block .io-label {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.event-reasoning {
  margin-top: 10px;
  padding: 10px 14px;
  background: var(--yellow-dim);
  border-radius: var(--radius-sm);
  border-left: 3px solid var(--yellow);
  font-size: 0.85rem;
  color: var(--text-primary);
}

.event-reasoning .reasoning-label {
  font-size: 0.7rem;
  color: var(--yellow);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 2px;
}

.event-stats {
  display: flex;
  gap: 16px;
  margin-top: 8px;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.event-stats span {
  display: flex;
  align-items: center;
  gap: 4px;
}

/* ── Charts ───────────────────────────────────────────────────────────── */

.charts-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-bottom: 20px;
}

.chart-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.chart-card h3 {
  font-size: 0.9rem;
  font-weight: 600;
  margin-bottom: 12px;
  color: var(--text-secondary);
}

.token-summary {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
}

.token-summary h3 {
  font-size: 0.9rem;
  margin-bottom: 12px;
  color: var(--text-secondary);
}

.token-table {
  width: 100%;
  border-collapse: collapse;
}

.token-table th, .token-table td {
  padding: 8px 12px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
}

.token-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 0.5px;
}

/* ── Explain Panel ────────────────────────────────────────────────────── */

.explain-panel {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  line-height: 1.8;
}

.explain-panel h2 {
  color: var(--accent);
  margin-bottom: 8px;
  font-size: 1.2rem;
}

.explain-panel h3 {
  color: var(--text-primary);
  margin-top: 16px;
  margin-bottom: 8px;
  font-size: 1rem;
}

.explain-panel strong {
  color: var(--text-primary);
}

.explain-panel em {
  color: var(--text-secondary);
}

.explain-panel ul, .explain-panel ol {
  padding-left: 20px;
}

.explain-panel li {
  margin-bottom: 4px;
}

/* ── Loading ──────────────────────────────────────────────────────────── */

.loading {
  text-align: center;
  padding: 40px;
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ── Export Controls ──────────────────────────────────────────────────── */

.export-controls {
  position: relative;
}

.export-dropdown {
  position: relative;
  display: inline-block;
}

.btn-export {
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--accent);
  background: rgba(88, 166, 255, 0.1);
  color: var(--accent);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
  display: flex;
  align-items: center;
  gap: 6px;
}

.btn-export:hover {
  background: rgba(88, 166, 255, 0.2);
  border-color: var(--accent-hover);
  color: var(--accent-hover);
}

.btn-export .caret {
  font-size: 0.7rem;
  transition: transform 0.15s ease;
}

.export-dropdown.open .btn-export .caret {
  transform: rotate(180deg);
}

.export-menu {
  display: none;
  position: absolute;
  right: 0;
  top: calc(100% + 4px);
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  min-width: 180px;
  z-index: 50;
  overflow: hidden;
}

.export-dropdown.open .export-menu {
  display: block;
}

.export-option {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px 16px;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  text-align: left;
  transition: background 0.1s ease;
}

.export-option:hover {
  background: var(--bg-tertiary);
}

.export-option:first-child {
  border-bottom: 1px solid var(--border);
}

.export-icon {
  font-size: 0.85rem;
  width: 20px;
  text-align: center;
  color: var(--text-muted);
}

.export-toast {
  position: fixed;
  bottom: 24px;
  right: 24px;
  padding: 12px 20px;
  background: var(--green-dim);
  border: 1px solid var(--green);
  border-radius: var(--radius);
  color: var(--green);
  font-size: 0.85rem;
  z-index: 200;
  animation: toastIn 0.3s ease, toastOut 0.3s ease 2.2s forwards;
}

@keyframes toastIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes toastOut {
  from { opacity: 1; transform: translateY(0); }
  to { opacity: 0; transform: translateY(10px); }
}

/* ── Responsive ───────────────────────────────────────────────────────── */

@media (max-width: 768px) {
  .main { padding: 16px; }
  .event-io { grid-template-columns: 1fr; }
  .charts-grid { grid-template-columns: 1fr; }
  .session-card { flex-direction: column; gap: 12px; align-items: flex-start; }
  .session-card-right { width: 100%; justify-content: space-between; }
  .view-header { flex-direction: column; gap: 12px; align-items: flex-start; }
  .compare-overview { grid-template-columns: repeat(2, 1fr); }
}

/* ── Compare Selection ────────────────────────────────────────────────── */

.session-search-panel {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 12px 16px;
  margin-bottom: 12px;
}

.session-search-panel .search-row {
  flex-wrap: wrap;
}

.compare-hint {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-bottom: 12px;
  padding: 0 4px;
}

.compare-checkbox {
  appearance: none;
  -webkit-appearance: none;
  width: 18px;
  height: 18px;
  border: 2px solid var(--border);
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.15s ease;
  flex-shrink: 0;
  position: relative;
}

.compare-checkbox:hover {
  border-color: var(--accent);
}

.compare-checkbox:checked {
  background: var(--accent);
  border-color: var(--accent);
}

.compare-checkbox:checked::after {
  content: '✓';
  position: absolute;
  color: white;
  font-size: 12px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.session-card.selected {
  border-color: var(--accent);
  background: rgba(88, 166, 255, 0.05);
}

.btn-compare {
  background: rgba(88, 166, 255, 0.1);
  border-color: var(--accent);
  color: var(--accent);
}

.btn-compare:hover {
  background: rgba(88, 166, 255, 0.2);
}

.btn-compare:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ── Compare View ─────────────────────────────────────────────────────── */

.compare-labels {
  display: flex;
  gap: 24px;
  margin-bottom: 20px;
}

.compare-label {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  font-size: 0.85rem;
  font-weight: 600;
}

.compare-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  flex-shrink: 0;
}

.dot-a { background: var(--accent); }
.dot-b { background: var(--orange); }

.compare-overview {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 12px;
  margin-bottom: 24px;
}

.compare-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.compare-card .compare-card-title {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 10px;
}

.compare-card .compare-values {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
}

.compare-val {
  text-align: center;
}

.compare-val .val-num {
  font-size: 1.2rem;
  font-weight: 700;
}

.compare-val.val-a .val-num { color: var(--accent); }
.compare-val.val-b .val-num { color: var(--orange); }

.compare-val .val-label {
  font-size: 0.65rem;
  color: var(--text-muted);
  text-transform: uppercase;
}

.compare-delta {
  text-align: center;
  font-size: 0.75rem;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.compare-delta.positive { color: var(--red); background: var(--red-dim); }
.compare-delta.negative { color: var(--green); background: var(--green-dim); }
.compare-delta.neutral { color: var(--text-muted); background: var(--bg-tertiary); }
.compare-delta.higher { color: var(--yellow); background: var(--yellow-dim); }

.compare-table {
  width: 100%;
  border-collapse: collapse;
}

.compare-table th, .compare-table td {
  padding: 10px 14px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
}

.compare-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.72rem;
  letter-spacing: 0.5px;
}

.compare-table .col-a { color: var(--accent); }
.compare-table .col-b { color: var(--orange); }

.compare-bar-container {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 20px;
}

.compare-bar {
  height: 14px;
  border-radius: 3px;
  min-width: 2px;
  transition: width 0.3s ease;
}

.compare-bar.bar-a { background: var(--accent); }
.compare-bar.bar-b { background: var(--orange); }

/* ── Analytics Panel ──────────────────────────────────────────────────── */

.btn-analytics {
  background: rgba(188, 140, 255, 0.1);
  border-color: var(--purple);
  color: var(--purple);
}

.btn-analytics:hover {
  background: rgba(188, 140, 255, 0.2);
  border-color: var(--purple);
}

.btn-analytics.active {
  background: rgba(188, 140, 255, 0.25);
  border-color: var(--purple);
  color: var(--purple);
}

.analytics-panel {
  margin-bottom: 20px;
  padding: 20px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  animation: slideDown 0.2s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

.analytics-loading {
  text-align: center;
  padding: 32px;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.analytics-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 10px;
  margin-bottom: 16px;
}

.analytics-stat {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  text-align: center;
}

.analytics-stat .stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.analytics-stat .stat-value.accent { color: var(--accent); }
.analytics-stat .stat-value.green { color: var(--green); }
.analytics-stat .stat-value.purple { color: var(--purple); }
.analytics-stat .stat-value.yellow { color: var(--yellow); }
.analytics-stat .stat-value.red { color: var(--red); }
.analytics-stat .stat-value.orange { color: var(--orange); }

.analytics-stat .stat-label {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-top: 4px;
}

.analytics-charts-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-bottom: 16px;
}

.analytics-chart {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
}

.analytics-tables-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

.analytics-table-card {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.analytics-table-card h3 {
  font-size: 0.85rem;
  font-weight: 600;
  margin-bottom: 10px;
  color: var(--text-secondary);
}

.analytics-table {
  width: 100%;
  border-collapse: collapse;
}

.analytics-table th,
.analytics-table td {
  padding: 6px 10px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.8rem;
}

.analytics-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.68rem;
  letter-spacing: 0.5px;
}

.analytics-table td {
  color: var(--text-secondary);
}

.analytics-table .model-name,
.analytics-table .agent-name {
  color: var(--text-primary);
  font-weight: 500;
}

.analytics-bar-bg {
  width: 100%;
  height: 6px;
  background: var(--bg-primary);
  border-radius: 3px;
  overflow: hidden;
}

.analytics-bar-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.3s ease;
}

.analytics-bar-fill.accent { background: var(--accent); }
.analytics-bar-fill.purple { background: var(--purple); }
.analytics-bar-fill.green { background: var(--green); }
.analytics-bar-fill.orange { background: var(--orange); }

/* ── Pricing Editor ──────────────────────────────────────────────────── */

.pricing-input {
  width: 100px;
  padding: 4px 8px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  font-family: monospace;
}

.pricing-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(88, 166, 255, 0.2);
}

.pricing-input::-webkit-inner-spin-button { opacity: 0.5; }

@media (max-width: 768px) {
  .analytics-charts-row { grid-template-columns: 1fr; }
  .analytics-tables-row { grid-template-columns: 1fr; }
  .analytics-cards { grid-template-columns: repeat(2, 1fr); }
}

/* ── Event Search & Filter ────────────────────────────────────────────── */

.event-search-bar {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 16px;
  margin-bottom: 16px;
}

.search-row {
  display: flex;
  gap: 8px;
  align-items: center;
}

.search-input-wrap {
  flex: 1;
  position: relative;
  display: flex;
  align-items: center;
}

.search-icon {
  position: absolute;
  left: 10px;
  font-size: 0.85rem;
  pointer-events: none;
  z-index: 1;
}

.search-text-input {
  width: 100%;
  padding: 8px 32px 8px 34px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  transition: border-color 0.15s ease;
}

.search-text-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(88, 166, 255, 0.15);
}

.search-text-input::placeholder {
  color: var(--text-muted);
}

.search-clear-btn {
  position: absolute;
  right: 6px;
  background: var(--bg-tertiary);
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 0.75rem;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.1s ease;
}

.search-clear-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.search-select {
  padding: 8px 12px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  min-width: 120px;
}

.search-select:focus {
  outline: none;
  border-color: var(--accent);
}

.btn-filter-toggle {
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-secondary);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
  white-space: nowrap;
}

.btn-filter-toggle:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.btn-filter-toggle.active {
  border-color: var(--accent);
  color: var(--accent);
  background: rgba(88, 166, 255, 0.1);
}

.advanced-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
  align-items: flex-end;
  animation: slideDown 0.15s ease;
}

.filter-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.filter-group label {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.filter-number-input {
  width: 100px;
  padding: 6px 8px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
}

.filter-number-input:focus {
  outline: none;
  border-color: var(--accent);
}

.filter-checkbox-label {
  display: flex !important;
  flex-direction: row !important;
  align-items: center;
  gap: 6px;
  font-size: 0.85rem !important;
  color: var(--text-secondary) !important;
  text-transform: none !important;
  letter-spacing: 0 !important;
  cursor: pointer;
  white-space: nowrap;
  padding-top: 4px;
}

.filter-checkbox-label input[type="checkbox"] {
  accent-color: var(--accent);
  cursor: pointer;
}

.btn-sm {
  padding: 6px 12px;
  font-size: 0.8rem;
  align-self: flex-end;
}

.search-results-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 10px;
  padding: 8px 12px;
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  font-size: 0.8rem;
  color: var(--text-secondary);
  animation: slideDown 0.15s ease;
}

.search-results-bar span:first-child {
  font-weight: 600;
  color: var(--text-primary);
}

/* Highlight matching events when search is active */
.timeline-event.search-highlight {
  border-color: var(--accent);
  box-shadow: 0 0 0 1px rgba(88, 166, 255, 0.3);
}

.timeline-event.search-dimmed {
  opacity: 0.3;
  pointer-events: none;
}

.search-match-text {
  background: rgba(88, 166, 255, 0.25);
  color: var(--accent-hover);
  border-radius: 2px;
  padding: 0 2px;
}

@media (max-width: 768px) {
  .search-row {
    flex-direction: column;
  }
  .search-select {
    width: 100%;
    min-width: unset;
  }
  .advanced-filters {
    flex-direction: column;
    gap: 8px;
  }
  .filter-number-input {
    width: 100%;
  }
}

/* ── Alert Rules ─────────────────────────────────────────────────────── */

.btn-alert-header {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 6px 14px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 6px;
  transition: background 0.2s, border-color 0.2s;
}
.btn-alert-header:hover {
  background: var(--bg-secondary);
  border-color: var(--accent);
}

.alert-badge {
  background: #f85149;
  color: #fff;
  font-size: 0.7rem;
  font-weight: 700;
  padding: 1px 6px;
  border-radius: 10px;
  min-width: 18px;
  text-align: center;
}

.alerts-modal {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
}

.alerts-modal-content {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 12px;
  width: 90%;
  max-width: 800px;
  max-height: 85vh;
  overflow-y: auto;
  padding: 24px;
}

.alerts-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}
.alerts-modal-header h2 { margin: 0; }

.alerts-summary {
  display: flex;
  gap: 12px;
  margin-bottom: 16px;
  flex-wrap: wrap;
}
.alert-stat-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  flex: 1;
  min-width: 120px;
  text-align: center;
}
.alert-stat-card .stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text-primary);
}
.alert-stat-card .stat-label {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 4px;
}

.alert-tab-content { display: none; }
.alert-tab-content.active { display: block; }

.alert-actions-bar {
  display: flex;
  gap: 8px;
  margin-bottom: 16px;
}

/* Rule Form */
.alert-rule-form {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 16px;
}
.alert-rule-form h3 { margin: 0 0 12px; }

.form-row {
  margin-bottom: 12px;
}
.form-row label, .form-row-inline label {
  display: block;
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-bottom: 4px;
}
.form-input, .form-select {
  width: 100%;
  padding: 8px 12px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 6px;
  color: var(--text-primary);
  font-size: 0.85rem;
}
.form-input:focus, .form-select:focus {
  outline: none;
  border-color: var(--accent);
}
.form-row-inline {
  display: flex;
  gap: 12px;
  margin-bottom: 12px;
}
.form-row-inline > div { flex: 1; }
.form-buttons {
  display: flex;
  gap: 8px;
  margin-top: 12px;
}

/* Rule Cards */
.alert-rule-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 14px 16px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
  transition: border-color 0.2s;
}
.alert-rule-card:hover { border-color: var(--accent); }
.alert-rule-card.disabled { opacity: 0.5; }

.rule-status-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}
.rule-status-dot.active { background: #3fb950; }
.rule-status-dot.disabled { background: #8b949e; }

.rule-info { flex: 1; min-width: 0; }
.rule-name {
  font-weight: 600;
  font-size: 0.9rem;
  margin-bottom: 4px;
}
.rule-condition {
  font-size: 0.8rem;
  color: var(--text-muted);
  font-family: monospace;
}

.rule-actions {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
}
.rule-actions button {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 4px 8px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.75rem;
}
.rule-actions button:hover {
  border-color: var(--accent);
  color: var(--text-primary);
}
.rule-actions .btn-danger:hover {
  border-color: #f85149;
  color: #f85149;
}

/* Alert History */
.alert-event-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
}
.alert-event-card.unacknowledged {
  border-left: 3px solid #f85149;
}
.alert-event-card.acknowledged {
  border-left: 3px solid #3fb950;
  opacity: 0.7;
}

.alert-event-info { flex: 1; }
.alert-event-rule {
  font-weight: 600;
  font-size: 0.85rem;
}
.alert-event-detail {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 2px;
}
.alert-event-time {
  font-size: 0.75rem;
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Evaluation result toast */
.alert-eval-result {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 12px;
}
.alert-eval-result .fired { color: #f85149; font-weight: 600; }
.alert-eval-result .ok { color: #3fb950; }
.alert-eval-result .cooldown { color: #d29922; }

/* ── Annotations ─────────────────────────────────────────────────── */

.annotations-toolbar {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 16px;
}

.annotation-form {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.annotation-textarea {
  width: 100%;
  background: var(--bg-secondary);
  color: var(--text-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px;
  font-family: inherit;
  font-size: 0.9rem;
  resize: vertical;
  margin-bottom: 10px;
}
.annotation-textarea:focus {
  outline: none;
  border-color: var(--accent);
}

.annotation-form-row {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.annotations-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.annotation-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  border-left: 3px solid var(--accent);
}
.annotation-bug { border-left-color: var(--red); }
.annotation-insight { border-left-color: var(--yellow); }
.annotation-warning { border-left-color: var(--orange); }
.annotation-milestone { border-left-color: var(--green); }
.annotation-note { border-left-color: var(--accent); }

.annotation-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.annotation-type-badge {
  font-weight: 600;
  text-transform: capitalize;
}

.annotation-author {
  color: var(--accent);
}

.annotation-time {
  margin-left: auto;
}

.annotation-delete {
  font-size: 0.8rem;
  padding: 2px 6px;
  opacity: 0.5;
}
.annotation-delete:hover {
  opacity: 1;
}

.annotation-body {
  font-size: 0.9rem;
  line-height: 1.5;
  white-space: pre-wrap;
  word-break: break-word;
}

/* ── Command Palette ─────────────────────────────────────────────── */

.command-palette-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  z-index: 10000;
  display: flex;
  justify-content: center;
  padding-top: 15vh;
  backdrop-filter: blur(2px);
}

.command-palette {
  background: #1e1e2e;
  border: 1px solid #45475a;
  border-radius: 12px;
  width: 560px;
  max-height: 420px;
  display: flex;
  flex-direction: column;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
  overflow: hidden;
}

.command-palette-input-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  border-bottom: 1px solid #313244;
}

.command-palette-icon {
  font-size: 1.1em;
  opacity: 0.6;
}

.command-palette-input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: #cdd6f4;
  font-size: 15px;
  font-family: inherit;
}

.command-palette-input::placeholder {
  color: #6c7086;
}

.command-palette-hint {
  background: #313244;
  color: #a6adc8;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-family: inherit;
}

.command-palette-results {
  overflow-y: auto;
  padding: 6px 0;
}

.command-palette-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  cursor: pointer;
  color: #cdd6f4;
  font-size: 14px;
  transition: background 0.1s;
}

.command-palette-item:hover,
.command-palette-item.active {
  background: #313244;
}

.command-palette-item-icon {
  font-size: 1.1em;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}

.command-palette-item-label {
  flex: 1;
  min-width: 0;
}

.command-palette-item-name {
  font-weight: 500;
}

.command-palette-item-desc {
  font-size: 12px;
  color: #6c7086;
  margin-top: 1px;
}

.command-palette-item-shortcut {
  color: #6c7086;
  font-size: 11px;
  flex-shrink: 0;
}

.command-palette-item-shortcut kbd {
  background: #313244;
  padding: 1px 6px;
  border-radius: 3px;
  font-family: inherit;
  font-size: 11px;
}

.command-palette-empty {
  padding: 24px 16px;
  text-align: center;
  color: #6c7086;
  font-size: 13px;
}

.command-palette-group {
  padding: 6px 16px 4px;
  font-size: 11px;
  color: #6c7086;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-weight: 600;
}

/* ── Error Analytics ────────────────────────────────────────────────── */

.error-high { color: #ef4444; }
.error-medium { color: #f97316; }
.error-low { color: #22c55e; }

.error-item {
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 10px;
  background: var(--bg-secondary);
}

.error-item:hover {
  border-color: rgba(239, 68, 68, 0.3);
}

.error-item-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.error-type-badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.error-badge-error { background: rgba(239, 68, 68, 0.2); color: #ef4444; }
.error-badge-tool_error { background: rgba(249, 115, 22, 0.2); color: #f97316; }
.error-badge-agent_error { background: rgba(234, 179, 8, 0.2); color: #eab308; }

.error-count {
  font-weight: 700;
  color: var(--text-muted);
  font-size: 0.85rem;
}

.error-model {
  font-size: 0.75rem;
  color: var(--text-muted);
  background: var(--bg-tertiary, rgba(255,255,255,0.05));
  padding: 2px 6px;
  border-radius: 3px;
}

.error-message {
  font-family: "SF Mono", "Cascadia Code", "Fira Code", monospace;
  font-size: 0.82rem;
  color: var(--text-secondary);
  padding: 6px 10px;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  word-break: break-word;
  margin-bottom: 6px;
}

.error-meta {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.empty-state h3 {
  color: var(--text-primary);
  margin-bottom: 8px;
}

.clickable-row {
  cursor: pointer;
}

.clickable-row:hover {
  background: rgba(255, 255, 255, 0.04);
}

/* ── Leaderboard Panel ─────────────────────────────────────────────── */
.leaderboard-panel {
  margin-bottom: 16px;
  padding: 16px;
  background: var(--card-bg, #161b22);
  border: 1px solid var(--border-color, #30363d);
  border-radius: 8px;
}
.leaderboard-controls {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  margin-bottom: 16px;
  align-items: center;
}
.leaderboard-controls label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: #8b949e;
}
.leaderboard-controls select {
  background: #0d1117;
  color: #c9d1d9;
  border: 1px solid #30363d;
  border-radius: 6px;
  padding: 4px 8px;
  font-size: 13px;
}
.leaderboard-table-wrap {
  overflow-x: auto;
}
.leaderboard-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
.leaderboard-table th {
  text-align: left;
  padding: 8px 12px;
  color: #8b949e;
  font-weight: 600;
  border-bottom: 1px solid #30363d;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
}
.leaderboard-table th:hover {
  color: #c9d1d9;
}
.leaderboard-table th.sorted {
  color: #58a6ff;
}
.leaderboard-table td {
  padding: 8px 12px;
  border-bottom: 1px solid #21262d;
  color: #c9d1d9;
  white-space: nowrap;
}
.leaderboard-table tr:hover td {
  background: #1c2128;
}
.leaderboard-rank {
  font-weight: 700;
  font-size: 14px;
  min-width: 40px;
  text-align: center;
}
.rank-medal { font-size: 16px; }
.leaderboard-agent {
  font-weight: 600;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
}
.leaderboard-bar {
  display: inline-block;
  height: 8px;
  border-radius: 4px;
  background: #238636;
  vertical-align: middle;
  margin-left: 6px;
  transition: width 0.3s ease;
}
.leaderboard-bar.speed { background: #58a6ff; }
.leaderboard-bar.cost { background: #f0883e; }
.leaderboard-bar.volume { background: #8b5cf6; }
.leaderboard-empty {
  text-align: center;
  padding: 32px;
  color: #8b949e;
}
.leaderboard-stat-label {
  color: #8b949e;
  font-size: 11px;
}

output.aggregated_output:
/* ── AgentLens Dashboard — Dark Theme ─────────────────────────────────── */

:root {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #21262d;
  --bg-hover: #30363d;
  --border: #30363d;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --accent: #58a6ff;
  --accent-hover: #79c0ff;
  --green: #3fb950;
  --green-dim: rgba(63, 185, 80, 0.15);
  --yellow: #d29922;
  --yellow-dim: rgba(210, 153, 34, 0.15);
  --red: #f85149;
  --red-dim: rgba(248, 81, 73, 0.15);
  --purple: #bc8cff;
  --purple-dim: rgba(188, 140, 255, 0.15);
  --orange: #f0883e;
  --orange-dim: rgba(240, 136, 62, 0.15);
  --radius: 8px;
  --radius-sm: 4px;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

/* ── Light Theme ──────────────────────────────────────────────────────── */

[data-theme="light"] {
  --bg-primary: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-tertiary: #eaeef2;
  --bg-hover: #d0d7de;
  --border: #d0d7de;
  --text-primary: #1f2328;
  --text-secondary: #656d76;
  --text-muted: #8b949e;
  --accent: #0969da;
  --accent-hover: #0550ae;
  --green: #1a7f37;
  --green-dim: rgba(26, 127, 55, 0.12);
  --yellow: #9a6700;
  --yellow-dim: rgba(154, 103, 0, 0.12);
  --red: #cf222e;
  --red-dim: rgba(207, 34, 46, 0.12);
  --purple: #8250df;
  --purple-dim: rgba(130, 80, 223, 0.12);
  --orange: #bc4c00;
  --orange-dim: rgba(188, 76, 0, 0.12);
  --shadow: 0 1px 3px rgba(31, 35, 40, 0.12);
}

/* Light-theme overrides for elements that use hard-coded colors */
[data-theme="light"] .command-palette { background: #f6f8fa; border-color: #d0d7de; }
[data-theme="light"] .command-palette-input { color: #1f2328; }
[data-theme="light"] .command-palette-input::placeholder { color: #8b949e; }
[data-theme="light"] .command-palette-item { color: #1f2328; }
[data-theme="light"] .command-palette-item:hover,
[data-theme="light"] .command-palette-item.active { background: #eaeef2; }
[data-theme="light"] .command-palette-hint { background: #eaeef2; color: #656d76; }
[data-theme="light"] .command-palette-input-row { border-bottom-color: #d0d7de; }
[data-theme="light"] .command-palette-item-desc { color: #8b949e; }
[data-theme="light"] .command-palette-item-shortcut { color: #8b949e; }
[data-theme="light"] .command-palette-item-shortcut kbd { background: #eaeef2; }
[data-theme="light"] .command-palette-empty { color: #8b949e; }
[data-theme="light"] .command-palette-group { color: #8b949e; }
[data-theme="light"] .error-message { background: rgba(0, 0, 0, 0.04); }
[data-theme="light"] .leaderboard-controls select { background: #ffffff; color: #1f2328; border-color: #d0d7de; }
[data-theme="light"] .leaderboard-table th { color: #656d76; }
[data-theme="light"] .leaderboard-table th.sorted { color: #0969da; }
[data-theme="light"] .leaderboard-table td { color: #1f2328; border-bottom-color: #eaeef2; }
[data-theme="light"] .leaderboard-table tr:hover td { background: #f6f8fa; }

/* ── Theme Toggle ────────────────────────────────────────────────────── */

.theme-toggle {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 6px 10px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 1rem;
  line-height: 1;
  transition: background 0.2s, border-color 0.2s;
}

.theme-toggle:hover {
  background: var(--bg-hover);
  border-color: var(--accent);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  min-height: 100vh;
}

/* ── Header ──────────────────────────────────────────────────────────── */

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 100;
}

.header-left {
  display: flex;
  align-items: baseline;
  gap: 12px;
}

.logo {
  font-size: 1.4rem;
  font-weight: 700;
  color: var(--text-primary);
}

.tagline {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--green);
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

/* ── Main ────────────────────────────────────────────────────────────── */

.main {
  max-width: 1200px;
  margin: 0 auto;
  padding: 24px;
}

/* ── Views ────────────────────────────────────────────────────────────── */

.view {
  display: none;
}

.view.active {
  display: block;
}

.view-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.view-header h2 {
  font-size: 1.3rem;
  font-weight: 600;
}

.view-actions {
  display: flex;
  gap: 8px;
}

/* ── Buttons ─────────────────────────────────────────────────────────── */

.btn {
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
}

.btn:hover {
  background: var(--bg-hover);
  border-color: var(--text-muted);
}

.btn-secondary {
  background: transparent;
}

#bookmarkFilterBtn.active {
  background: var(--accent);
  color: #000;
  border-color: var(--accent);
}

.bookmark-star {
  transition: transform 0.15s ease;
}
.bookmark-star:hover {
  transform: scale(1.3);
}

.btn-ghost {
  background: transparent;
  border: none;
  color: var(--accent);
  padding: 8px 12px;
}

.btn-ghost:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

.select-input {
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
}

/* ── Session List ────────────────────────────────────────────────────── */

.session-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.session-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px 20px;
  cursor: pointer;
  transition: all 0.15s ease;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.session-card:hover {
  border-color: var(--accent);
  background: var(--bg-tertiary);
}

.session-card-left {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.session-agent {
  font-weight: 600;
  font-size: 1rem;
}

.session-meta {
  font-size: 0.8rem;
  color: var(--text-secondary);
  display: flex;
  gap: 16px;
}

.session-card-right {
  display: flex;
  align-items: center;
  gap: 16px;
}

.session-tokens {
  text-align: right;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.session-tokens .count {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-primary);
}

.status-badge {
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.status-badge.active {
  background: var(--green-dim);
  color: var(--green);
}

.status-badge.completed {
  background: var(--purple-dim);
  color: var(--purple);
}

.status-badge.error {
  background: var(--red-dim);
  color: var(--red);
}

/* ── Session Info Bar ────────────────────────────────────────────────── */

.session-info-bar {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 12px;
  margin-bottom: 20px;
}

.info-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
}

.info-card .label {
  font-size: 0.75rem;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.info-card .value {
  font-size: 1.1rem;
  font-weight: 600;
}

/* ── Tabs ─────────────────────────────────────────────────────────────── */

.tabs {
  display: flex;
  gap: 2px;
  margin-bottom: 20px;
  border-bottom: 1px solid var(--border);
}

.tab {
  padding: 10px 20px;
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.15s ease;
}

.tab:hover {
  color: var(--text-primary);
}

.tab.active {
  color: var(--accent);
  border-bottom-color: var(--accent);
}

.tab-content {
  display: none;
}

.tab-content.active {
  display: block;
}

/* ── Timeline ─────────────────────────────────────────────────────────── */

.timeline {
  position: relative;
  padding-left: 32px;
}

.timeline::before {
  content: '';
  position: absolute;
  left: 12px;
  top: 0;
  bottom: 0;
  width: 2px;
  background: var(--border);
}

.timeline-event {
  position: relative;
  margin-bottom: 16px;
  padding: 14px 18px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  transition: all 0.15s ease;
}

.timeline-event:hover {
  border-color: var(--text-muted);
}

.timeline-event::before {
  content: '';
  position: absolute;
  left: -26px;
  top: 20px;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  border: 2px solid var(--border);
  background: var(--bg-primary);
}

.timeline-event.llm_call::before { background: var(--accent); border-color: var(--accent); }
.timeline-event.tool_call::before { background: var(--orange); border-color: var(--orange); }
.timeline-event.agent_call::before { background: var(--green); border-color: var(--green); }
.timeline-event.agent_error::before, .timeline-event.tool_error::before { background: var(--red); border-color: var(--red); }

.event-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.event-type {
  display: flex;
  align-items: center;
  gap: 8px;
}

.event-type-badge {
  padding: 3px 8px;
  border-radius: var(--radius-sm);
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
}

.event-type-badge.llm_call { background: rgba(88, 166, 255, 0.15); color: var(--accent); }
.event-type-badge.tool_call { background: var(--orange-dim); color: var(--orange); }
.event-type-badge.agent_call { background: var(--green-dim); color: var(--green); }
.event-type-badge.agent_error, .event-type-badge.tool_error { background: var(--red-dim); color: var(--red); }

.event-model {
  font-size: 0.8rem;
  color: var(--text-secondary);
  background: var(--bg-tertiary);
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.event-time {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.event-body {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.event-io {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-top: 8px;
}

.event-io-block {
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  font-family: 'SF Mono', Consolas, monospace;
  font-size: 0.8rem;
  color: var(--text-secondary);
  overflow: hidden;
  max-height: 120px;
  overflow-y: auto;
}

.event-io-block .io-label {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.event-reasoning {
  margin-top: 10px;
  padding: 10px 14px;
  background: var(--yellow-dim);
  border-radius: var(--radius-sm);
  border-left: 3px solid var(--yellow);
  font-size: 0.85rem;
  color: var(--text-primary);
}

.event-reasoning .reasoning-label {
  font-size: 0.7rem;
  color: var(--yellow);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 2px;
}

.event-stats {
  display: flex;
  gap: 16px;
  margin-top: 8px;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.event-stats span {
  display: flex;
  align-items: center;
  gap: 4px;
}

/* ── Charts ───────────────────────────────────────────────────────────── */

.charts-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-bottom: 20px;
}

.chart-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.chart-card h3 {
  font-size: 0.9rem;
  font-weight: 600;
  margin-bottom: 12px;
  color: var(--text-secondary);
}

.token-summary {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
}

.token-summary h3 {
  font-size: 0.9rem;
  margin-bottom: 12px;
  color: var(--text-secondary);
}

.token-table {
  width: 100%;
  border-collapse: collapse;
}

.token-table th, .token-table td {
  padding: 8px 12px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
}

.token-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 0.5px;
}

/* ── Explain Panel ────────────────────────────────────────────────────── */

.explain-panel {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  line-height: 1.8;
}

.explain-panel h2 {
  color: var(--accent);
  margin-bottom: 8px;
  font-size: 1.2rem;
}

.explain-panel h3 {
  color: var(--text-primary);
  margin-top: 16px;
  margin-bottom: 8px;
  font-size: 1rem;
}

.explain-panel strong {
  color: var(--text-primary);
}

.explain-panel em {
  color: var(--text-secondary);
}

.explain-panel ul, .explain-panel ol {
  padding-left: 20px;
}

.explain-panel li {
  margin-bottom: 4px;
}

/* ── Loading ──────────────────────────────────────────────────────────── */

.loading {
  text-align: center;
  padding: 40px;
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ── Export Controls ──────────────────────────────────────────────────── */

.export-controls {
  position: relative;
}

.export-dropdown {
  position: relative;
  display: inline-block;
}

.btn-export {
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--accent);
  background: rgba(88, 166, 255, 0.1);
  color: var(--accent);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
  display: flex;
  align-items: center;
  gap: 6px;
}

.btn-export:hover {
  background: rgba(88, 166, 255, 0.2);
  border-color: var(--accent-hover);
  color: var(--accent-hover);
}

.btn-export .caret {
  font-size: 0.7rem;
  transition: transform 0.15s ease;
}

.export-dropdown.open .btn-export .caret {
  transform: rotate(180deg);
}

.export-menu {
  display: none;
  position: absolute;
  right: 0;
  top: calc(100% + 4px);
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  min-width: 180px;
  z-index: 50;
  overflow: hidden;
}

.export-dropdown.open .export-menu {
  display: block;
}

.export-option {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px 16px;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  text-align: left;
  transition: background 0.1s ease;
}

.export-option:hover {
  background: var(--bg-tertiary);
}

.export-option:first-child {
  border-bottom: 1px solid var(--border);
}

.export-icon {
  font-size: 0.85rem;
  width: 20px;
  text-align: center;
  color: var(--text-muted);
}

.export-toast {
  position: fixed;
  bottom: 24px;
  right: 24px;
  padding: 12px 20px;
  background: var(--green-dim);
  border: 1px solid var(--green);
  border-radius: var(--radius);
  color: var(--green);
  font-size: 0.85rem;
  z-index: 200;
  animation: toastIn 0.3s ease, toastOut 0.3s ease 2.2s forwards;
}

@keyframes toastIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes toastOut {
  from { opacity: 1; transform: translateY(0); }
  to { opacity: 0; transform: translateY(10px); }
}

/* ── Responsive ───────────────────────────────────────────────────────── */

@media (max-width: 768px) {
  .main { padding: 16px; }
  .event-io { grid-template-columns: 1fr; }
  .charts-grid { grid-template-columns: 1fr; }
  .session-card { flex-direction: column; gap: 12px; align-items: flex-start; }
  .session-card-right { width: 100%; justify-content: space-between; }
  .view-header { flex-direction: column; gap: 12px; align-items: flex-start; }
  .compare-overview { grid-template-columns: repeat(2, 1fr); }
}

/* ── Compare Selection ────────────────────────────────────────────────── */

.session-search-panel {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 12px 16px;
  margin-bottom: 12px;
}

.session-search-panel .search-row {
  flex-wrap: wrap;
}

.compare-hint {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-bottom: 12px;
  padding: 0 4px;
}

.compare-checkbox {
  appearance: none;
  -webkit-appearance: none;
  width: 18px;
  height: 18px;
  border: 2px solid var(--border);
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.15s ease;
  flex-shrink: 0;
  position: relative;
}

.compare-checkbox:hover {
  border-color: var(--accent);
}

.compare-checkbox:checked {
  background: var(--accent);
  border-color: var(--accent);
}

.compare-checkbox:checked::after {
  content: '✓';
  position: absolute;
  color: white;
  font-size: 12px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.session-card.selected {
  border-color: var(--accent);
  background: rgba(88, 166, 255, 0.05);
}

.btn-compare {
  background: rgba(88, 166, 255, 0.1);
  border-color: var(--accent);
  color: var(--accent);
}

.btn-compare:hover {
  background: rgba(88, 166, 255, 0.2);
}

.btn-compare:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ── Compare View ─────────────────────────────────────────────────────── */

.compare-labels {
  display: flex;
  gap: 24px;
  margin-bottom: 20px;
}

.compare-label {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  font-size: 0.85rem;
  font-weight: 600;
}

.compare-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  flex-shrink: 0;
}

.dot-a { background: var(--accent); }
.dot-b { background: var(--orange); }

.compare-overview {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 12px;
  margin-bottom: 24px;
}

.compare-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.compare-card .compare-card-title {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 10px;
}

.compare-card .compare-values {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
}

.compare-val {
  text-align: center;
}

.compare-val .val-num {
  font-size: 1.2rem;
  font-weight: 700;
}

.compare-val.val-a .val-num { color: var(--accent); }
.compare-val.val-b .val-num { color: var(--orange); }

.compare-val .val-label {
  font-size: 0.65rem;
  color: var(--text-muted);
  text-transform: uppercase;
}

.compare-delta {
  text-align: center;
  font-size: 0.75rem;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.compare-delta.positive { color: var(--red); background: var(--red-dim); }
.compare-delta.negative { color: var(--green); background: var(--green-dim); }
.compare-delta.neutral { color: var(--text-muted); background: var(--bg-tertiary); }
.compare-delta.higher { color: var(--yellow); background: var(--yellow-dim); }

.compare-table {
  width: 100%;
  border-collapse: collapse;
}

.compare-table th, .compare-table td {
  padding: 10px 14px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
}

.compare-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.72rem;
  letter-spacing: 0.5px;
}

.compare-table .col-a { color: var(--accent); }
.compare-table .col-b { color: var(--orange); }

.compare-bar-container {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 20px;
}

.compare-bar {
  height: 14px;
  border-radius: 3px;
  min-width: 2px;
  transition: width 0.3s ease;
}

.compare-bar.bar-a { background: var(--accent); }
.compare-bar.bar-b { background: var(--orange); }

/* ── Analytics Panel ──────────────────────────────────────────────────── */

.btn-analytics {
  background: rgba(188, 140, 255, 0.1);
  border-color: var(--purple);
  color: var(--purple);
}

.btn-analytics:hover {
  background: rgba(188, 140, 255, 0.2);
  border-color: var(--purple);
}

.btn-analytics.active {
  background: rgba(188, 140, 255, 0.25);
  border-color: var(--purple);
  color: var(--purple);
}

.analytics-panel {
  margin-bottom: 20px;
  padding: 20px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  animation: slideDown 0.2s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

.analytics-loading {
  text-align: center;
  padding: 32px;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.analytics-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 10px;
  margin-bottom: 16px;
}

.analytics-stat {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  text-align: center;
}

.analytics-stat .stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.analytics-stat .stat-value.accent { color: var(--accent); }
.analytics-stat .stat-value.green { color: var(--green); }
.analytics-stat .stat-value.purple { color: var(--purple); }
.analytics-stat .stat-value.yellow { color: var(--yellow); }
.analytics-stat .stat-value.red { color: var(--red); }
.analytics-stat .stat-value.orange { color: var(--orange); }

.analytics-stat .stat-label {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-top: 4px;
}

.analytics-charts-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-bottom: 16px;
}

.analytics-chart {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
}

.analytics-tables-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

.analytics-table-card {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

.analytics-table-card h3 {
  font-size: 0.85rem;
  font-weight: 600;
  margin-bottom: 10px;
  color: var(--text-secondary);
}

.analytics-table {
  width: 100%;
  border-collapse: collapse;
}

.analytics-table th,
.analytics-table td {
  padding: 6px 10px;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.8rem;
}

.analytics-table th {
  color: var(--text-muted);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.68rem;
  letter-spacing: 0.5px;
}

.analytics-table td {
  color: var(--text-secondary);
}

.analytics-table .model-name,
.analytics-table .agent-name {
  color: var(--text-primary);
  font-weight: 500;
}

.analytics-bar-bg {
  width: 100%;
  height: 6px;
  background: var(--bg-primary);
  border-radius: 3px;
  overflow: hidden;
}

.analytics-bar-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.3s ease;
}

.analytics-bar-fill.accent { background: var(--accent); }
.analytics-bar-fill.purple { background: var(--purple); }
.analytics-bar-fill.green { background: var(--green); }
.analytics-bar-fill.orange { background: var(--orange); }

/* ── Pricing Editor ──────────────────────────────────────────────────── */

.pricing-input {
  width: 100px;
  padding: 4px 8px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  font-family: monospace;
}

.pricing-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(88, 166, 255, 0.2);
}

.pricing-input::-webkit-inner-spin-button { opacity: 0.5; }

@media (max-width: 768px) {
  .analytics-charts-row { grid-template-columns: 1fr; }
  .analytics-tables-row { grid-template-columns: 1fr; }
  .analytics-cards { grid-template-columns: repeat(2, 1fr); }
}

/* ── Event Search & Filter ────────────────────────────────────────────── */

.event-search-bar {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 16px;
  margin-bottom: 16px;
}

.search-row {
  display: flex;
  gap: 8px;
  align-items: center;
}

.search-input-wrap {
  flex: 1;
  position: relative;
  display: flex;
  align-items: center;
}

.search-icon {
  position: absolute;
  left: 10px;
  font-size: 0.85rem;
  pointer-events: none;
  z-index: 1;
}

.search-text-input {
  width: 100%;
  padding: 8px 32px 8px 34px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  transition: border-color 0.15s ease;
}

.search-text-input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(88, 166, 255, 0.15);
}

.search-text-input::placeholder {
  color: var(--text-muted);
}

.search-clear-btn {
  position: absolute;
  right: 6px;
  background: var(--bg-tertiary);
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 0.75rem;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.1s ease;
}

.search-clear-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.search-select {
  padding: 8px 12px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
  cursor: pointer;
  min-width: 120px;
}

.search-select:focus {
  outline: none;
  border-color: var(--accent);
}

.btn-filter-toggle {
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg-tertiary);
  color: var(--text-secondary);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s ease;
  white-space: nowrap;
}

.btn-filter-toggle:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.btn-filter-toggle.active {
  border-color: var(--accent);
  color: var(--accent);
  background: rgba(88, 166, 255, 0.1);
}

.advanced-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
  align-items: flex-end;
  animation: slideDown 0.15s ease;
}

.filter-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.filter-group label {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.filter-number-input {
  width: 100px;
  padding: 6px 8px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-size: 0.85rem;
}

.filter-number-input:focus {
  outline: none;
  border-color: var(--accent);
}

.filter-checkbox-label {
  display: flex !important;
  flex-direction: row !important;
  align-items: center;
  gap: 6px;
  font-size: 0.85rem !important;
  color: var(--text-secondary) !important;
  text-transform: none !important;
  letter-spacing: 0 !important;
  cursor: pointer;
  white-space: nowrap;
  padding-top: 4px;
}

.filter-checkbox-label input[type="checkbox"] {
  accent-color: var(--accent);
  cursor: pointer;
}

.btn-sm {
  padding: 6px 12px;
  font-size: 0.8rem;
  align-self: flex-end;
}

.search-results-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 10px;
  padding: 8px 12px;
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  font-size: 0.8rem;
  color: var(--text-secondary);
  animation: slideDown 0.15s ease;
}

.search-results-bar span:first-child {
  font-weight: 600;
  color: var(--text-primary);
}

/* Highlight matching events when search is active */
.timeline-event.search-highlight {
  border-color: var(--accent);
  box-shadow: 0 0 0 1px rgba(88, 166, 255, 0.3);
}

.timeline-event.search-dimmed {
  opacity: 0.3;
  pointer-events: none;
}

.search-match-text {
  background: rgba(88, 166, 255, 0.25);
  color: var(--accent-hover);
  border-radius: 2px;
  padding: 0 2px;
}

@media (max-width: 768px) {
  .search-row {
    flex-direction: column;
  }
  .search-select {
    width: 100%;
    min-width: unset;
  }
  .advanced-filters {
    flex-direction: column;
    gap: 8px;
  }
  .filter-number-input {
    width: 100%;
  }
}

/* ── Alert Rules ─────────────────────────────────────────────────────── */

.btn-alert-header {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 6px 14px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 6px;
  transition: background 0.2s, border-color 0.2s;
}
.btn-alert-header:hover {
  background: var(--bg-secondary);
  border-color: var(--accent);
}

.alert-badge {
  background: #f85149;
  color: #fff;
  font-size: 0.7rem;
  font-weight: 700;
  padding: 1px 6px;
  border-radius: 10px;
  min-width: 18px;
  text-align: center;
}

.alerts-modal {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
}

.alerts-modal-content {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 12px;
  width: 90%;
  max-width: 800px;
  max-height: 85vh;
  overflow-y: auto;
  padding: 24px;
}

.alerts-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}
.alerts-modal-header h2 { margin: 0; }

.alerts-summary {
  display: flex;
  gap: 12px;
  margin-bottom: 16px;
  flex-wrap: wrap;
}
.alert-stat-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  flex: 1;
  min-width: 120px;
  text-align: center;
}
.alert-stat-card .stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text-primary);
}
.alert-stat-card .stat-label {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 4px;
}

.alert-tab-content { display: none; }
.alert-tab-content.active { display: block; }

.alert-actions-bar {
  display: flex;
  gap: 8px;
  margin-bottom: 16px;
}

/* Rule Form */
.alert-rule-form {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 16px;
}
.alert-rule-form h3 { margin: 0 0 12px; }

.form-row {
  margin-bottom: 12px;
}
.form-row label, .form-row-inline label {
  display: block;
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-bottom: 4px;
}
.form-input, .form-select {
  width: 100%;
  padding: 8px 12px;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 6px;
  color: var(--text-primary);
  font-size: 0.85rem;
}
.form-input:focus, .form-select:focus {
  outline: none;
  border-color: var(--accent);
}
.form-row-inline {
  display: flex;
  gap: 12px;
  margin-bottom: 12px;
}
.form-row-inline > div { flex: 1; }
.form-buttons {
  display: flex;
  gap: 8px;
  margin-top: 12px;
}

/* Rule Cards */
.alert-rule-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 14px 16px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
  transition: border-color 0.2s;
}
.alert-rule-card:hover { border-color: var(--accent); }
.alert-rule-card.disabled { opacity: 0.5; }

.rule-status-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}
.rule-status-dot.active { background: #3fb950; }
.rule-status-dot.disabled { background: #8b949e; }

.rule-info { flex: 1; min-width: 0; }
.rule-name {
  font-weight: 600;
  font-size: 0.9rem;
  margin-bottom: 4px;
}
.rule-condition {
  font-size: 0.8rem;
  color: var(--text-muted);
  font-family: monospace;
}

.rule-actions {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
}
.rule-actions button {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 4px 8px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.75rem;
}
.rule-actions button:hover {
  border-color: var(--accent);
  color: var(--text-primary);
}
.rule-actions .btn-danger:hover {
  border-color: #f85149;
  color: #f85149;
}

/* Alert History */
.alert-event-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
}
.alert-event-card.unacknowledged {
  border-left: 3px solid #f85149;
}
.alert-event-card.acknowledged {
  border-left: 3px solid #3fb950;
  opacity: 0.7;
}

.alert-event-info { flex: 1; }
.alert-event-rule {
  font-weight: 600;
  font-size: 0.85rem;
}
.alert-event-detail {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 2px;
}
.alert-event-time {
  font-size: 0.75rem;
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Evaluation result toast */
.alert-eval-result {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 12px;
}
.alert-eval-result .fired { color: #f85149; font-weight: 600; }
.alert-eval-result .ok { color: #3fb950; }
.alert-eval-result .cooldown { color: #d29922; }

/* ── Annotations ─────────────────────────────────────────────────── */

.annotations-toolbar {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 16px;
}

.annotation-form {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.annotation-textarea {
  width: 100%;
  background: var(--bg-secondary);
  color: var(--text-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px;
  font-family: inherit;
  font-size: 0.9rem;
  resize: vertical;
  margin-bottom: 10px;
}
.annotation-textarea:focus {
  outline: none;
  border-color: var(--accent);
}

.annotation-form-row {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.annotations-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.annotation-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  border-left: 3px solid var(--accent);
}
.annotation-bug { border-left-color: var(--red); }
.annotation-insight { border-left-color: var(--yellow); }
.annotation-warning { border-left-color: var(--orange); }
.annotation-milestone { border-left-color: var(--green); }
.annotation-note { border-left-color: var(--accent); }

.annotation-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.annotation-type-badge {
  font-weight: 600;
  text-transform: capitalize;
}

.annotation-author {
  color: var(--accent);
}

.annotation-time {
  margin-left: auto;
}

.annotation-delete {
  font-size: 0.8rem;
  padding: 2px 6px;
  opacity: 0.5;
}
.annotation-delete:hover {
  opacity: 1;
}

.annotation-body {
  font-size: 0.9rem;
  line-height: 1.5;
  white-space: pre-wrap;
  word-break: break-word;
}

/* ── Command Palette ─────────────────────────────────────────────── */

.command-palette-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  z-index: 10000;
  display: flex;
  justify-content: center;
  padding-top: 15vh;
  backdrop-filter: blur(2px);
}

.command-palette {
  background: #1e1e2e;
  border: 1px solid #45475a;
  border-radius: 12px;
  width: 560px;
  max-height: 420px;
  display: flex;
  flex-direction: column;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
  overflow: hidden;
}

.command-palette-input-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  border-bottom: 1px solid #313244;
}

.command-palette-icon {
  font-size: 1.1em;
  opacity: 0.6;
}

.command-palette-input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: #cdd6f4;
  font-size: 15px;
  font-family: inherit;
}

.command-palette-input::placeholder {
  color: #6c7086;
}

.command-palette-hint {
  background: #313244;
  color: #a6adc8;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-family: inherit;
}

.command-palette-results {
  overflow-y: auto;
  padding: 6px 0;
}

.command-palette-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  cursor: pointer;
  color: #cdd6f4;
  font-size: 14px;
  transition: background 0.1s;
}

.command-palette-item:hover,
.command-palette-item.active {
  background: #313244;
}

.command-palette-item-icon {
  font-size: 1.1em;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}

.command-palette-item-label {
  flex: 1;
  min-width: 0;
}

.command-palette-item-name {
  font-weight: 500;
}

.command-palette-item-desc {
  font-size: 12px;
  color: #6c7086;
  margin-top: 1px;
}

.command-palette-item-shortcut {
  color: #6c7086;
  font-size: 11px;
  flex-shrink: 0;
}

.command-palette-item-shortcut kbd {
  background: #313244;
  padding: 1px 6px;
  border-radius: 3px;
  font-family: inherit;
  font-size: 11px;
}

.command-palette-empty {
  padding: 24px 16px;
  text-align: center;
  color: #6c7086;
  font-size: 13px;
}

.command-palette-group {
  padding: 6px 16px 4px;
  font-size: 11px;
  color: #6c7086;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-weight: 600;
}

/* ── Error Analytics ────────────────────────────────────────────────── */

.error-high { color: #ef4444; }
.error-medium { color: #f97316; }
.error-low { color: #22c55e; }

.error-item {
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 10px;
  background: var(--bg-secondary);
}

.error-item:hover {
  border-color: rgba(239, 68, 68, 0.3);
}

.error-item-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.error-type-badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.error-badge-error { background: rgba(239, 68, 68, 0.2); color: #ef4444; }
.error-badge-tool_error { background: rgba(249, 115, 22, 0.2); color: #f97316; }
.error-badge-agent_error { background: rgba(234, 179, 8, 0.2); color: #eab308; }

.error-count {
  font-weight: 700;
  color: var(--text-muted);
  font-size: 0.85rem;
}

.error-model {
  font-size: 0.75rem;
  color: var(--text-muted);
  background: var(--bg-tertiary, rgba(255,255,255,0.05));
  padding: 2px 6px;
  border-radius: 3px;
}

.error-message {
  font-family: "SF Mono", "Cascadia Code", "Fira Code", monospace;
  font-size: 0.82rem;
  color: var(--text-secondary);
  padding: 6px 10px;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  word-break: break-word;
  margin-bottom: 6px;
}

.error-meta {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.empty-state h3 {
  color: var(--text-primary);
  margin-bottom: 8px;
}

.clickable-row {
  cursor: pointer;
}

.clickable-row:hover {
  background: rgba(255, 255, 255, 0.04);
}

/* ── Leaderboard Panel ─────────────────────────────────────────────── */
.leaderboard-panel {
  margin-bottom: 16px;
  padding: 16px;
  background: var(--card-bg, #161b22);
  border: 1px solid var(--border-color, #30363d);
  border-radius: 8px;
}
.leaderboard-controls {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  margin-bottom: 16px;
  align-items: center;
}
.leaderboard-controls label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: #8b949e;
}
.leaderboard-controls select {
  background: #0d1117;
  color: #c9d1d9;
  border: 1px solid #30363d;
  border-radius: 6px;
  padding: 4px 8px;
  font-size: 13px;
}
.leaderboard-table-wrap {
  overflow-x: auto;
}
.leaderboard-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
.leaderboard-table th {
  text-align: left;
  padding: 8px 12px;
  color: #8b949e;
  font-weight: 600;
  border-bottom: 1px solid #30363d;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
}
.leaderboard-table th:hover {
  color: #c9d1d9;
}
.leaderboard-table th.sorted {
  color: #58a6ff;
}
.leaderboard-table td {
  padding: 8px 12px;
  border-bottom: 1px solid #21262d;
  color: #c9d1d9;
  white-space: nowrap;
}
.leaderboard-table tr:hover td {
  background: #1c2128;
}
.leaderboard-rank {
  font-weight: 700;
  font-size: 14px;
  min-width: 40px;
  text-align: center;
}
.rank-medal { font-size: 16px; }
.leaderboard-agent {
  font-weight: 600;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
}
.leaderboard-bar {
  display: inline-block;
  height: 8px;
  border-radius: 4px;
  background: #238636;
  vertical-align: middle;
  margin-left: 6px;
  transition: width 0.3s ease;
}
.leaderboard-bar.speed { background: #58a6ff; }
.leaderboard-bar.cost { background: #f0883e; }
.leaderboard-bar.volume { background: #8b5cf6; }
.leaderboard-empty {
  text-align: center;
  padding: 32px;
  color: #8b949e;
}
.leaderboard-stat-label {
  color: #8b949e;
  font-size: 11px;
}

