  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
}
.alert-event-card.unacknowledged {
  border-left: 3px solid #f85149;
}
.alert-event-card.acknowledged {
  border-left: 3px solid #3fb950;
  opacity: 0.7;
}

.alert-event-info { flex: 1; }
.alert-event-rule {
  font-weight: 600;
  font-size: 0.85rem;
}
.alert-event-detail {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 2px;
}
.alert-event-time {
  font-size: 0.75rem;
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Evaluation result toast */
.alert-eval-result {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 12px;
}
.alert-eval-result .fired { color: #f85149; font-weight: 600; }
.alert-eval-result .ok { color: #3fb950; }
.alert-eval-result .cooldown { color: #d29922; }

/* ── Annotations ─────────────────────────────────────────────────── */

.annotations-toolbar {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 16px;
}

.annotation-form {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.annotation-textarea {
  width: 100%;
  background: var(--bg-secondary);
  color: var(--text-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px;
  font-family: inherit;
  font-size: 0.9rem;
  resize: vertical;
  margin-bottom: 10px;
}
.annotation-textarea:focus {
  outline: none;
  border-color: var(--accent);
}

.annotation-form-row {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.annotations-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.annotation-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  border-left: 3px solid var(--accent);
}
.annotation-bug { border-left-color: var(--red); }
.annotation-insight { border-left-color: var(--yellow); }
.annotation-warning { border-left-color: var(--orange); }
.annotation-milestone { border-left-color: var(--green); }
.annotation-note { border-left-color: var(--accent); }

.annotation-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.annotation-type-badge {
  font-weight: 600;
  text-transform: capitalize;
}

.annotation-author {
  color: var(--accent);
}

.annotation-time {
  margin-left: auto;
}

.annotation-delete {
  font-size: 0.8rem;
  padding: 2px 6px;
  opacity: 0.5;
}
.annotation-delete:hover {
  opacity: 1;
}

.annotation-body {
  font-size: 0.9rem;
  line-height: 1.5;
  white-space: pre-wrap;
  word-break: break-word;
}

/* ── Command Palette ─────────────────────────────────────────────── */

.command-palette-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  z-index: 10000;
  display: flex;
  justify-content: center;
  padding-top: 15vh;
  backdrop-filter: blur(2px);
}

.command-palette {
  background: #1e1e2e;
  border: 1px solid #45475a;
  border-radius: 12px;
  width: 560px;
  max-height: 420px;
  display: flex;
  flex-direction: column;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
  overflow: hidden;
}

.command-palette-input-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  border-bottom: 1px solid #313244;
}

.command-palette-icon {
  font-size: 1.1em;
  opacity: 0.6;
}

.command-palette-input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: #cdd6f4;
  font-size: 15px;
  font-family: inherit;
}

.command-palette-input::placeholder {
  color: #6c7086;
}

.command-palette-hint {
  background: #313244;
  color: #a6adc8;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-family: inherit;
}

.command-palette-results {
  overflow-y: auto;
  padding: 6px 0;
}

.command-palette-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  cursor: pointer;
  color: #cdd6f4;
  font-size: 14px;
  transition: background 0.1s;
}

.command-palette-item:hover,
.command-palette-item.active {
  background: #313244;
}

.command-palette-item-icon {
  font-size: 1.1em;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}

.command-palette-item-label {
  flex: 1;
  min-width: 0;
}

.command-palette-item-name {
  font-weight: 500;
}

.command-palette-item-desc {
  font-size: 12px;
  color: #6c7086;
  margin-top: 1px;
}

.command-palette-item-shortcut {
  color: #6c7086;
  font-size: 11px;
  flex-shrink: 0;
}

.command-palette-item-shortcut kbd {
  background: #313244;
  padding: 1px 6px;
  border-radius: 3px;
  font-family: inherit;
  font-size: 11px;
}

.command-palette-empty {
  padding: 24px 16px;
  text-align: center;
  color: #6c7086;
  font-size: 13px;
}

.command-palette-group {
  padding: 6px 16px 4px;
  font-size: 11px;
  color: #6c7086;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-weight: 600;
}

/* ── Error Analytics ────────────────────────────────────────────────── */

.error-high { color: #ef4444; }
.error-medium { color: #f97316; }
.error-low { color: #22c55e; }

.error-item {
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 10px;
  background: var(--bg-secondary);
}

.error-item:hover {
  border-color: rgba(239, 68, 68, 0.3);
}

.error-item-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.error-type-badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.error-badge-error { background: rgba(239, 68, 68, 0.2); color: #ef4444; }
.error-badge-tool_error { background: rgba(249, 115, 22, 0.2); color: #f97316; }
.error-badge-agent_error { background: rgba(234, 179, 8, 0.2); color: #eab308; }

.error-count {
  font-weight: 700;
  color: var(--text-muted);
  font-size: 0.85rem;
}

.error-model {
  font-size: 0.75rem;
  color: var(--text-muted);
  background: var(--bg-tertiary, rgba(255,255,255,0.05));
  padding: 2px 6px;
  border-radius: 3px;
}

.error-message {
  font-family: "SF Mono", "Cascadia Code", "Fira Code", monospace;
  font-size: 0.82rem;
  color: var(--text-secondary);
  padding: 6px 10px;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  word-break: break-word;
  margin-bottom: 6px;
}

.error-meta {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.empty-state h3 {
  color: var(--text-primary);
  margin-bottom: 8px;
}

.clickable-row {
  cursor: pointer;
}

.clickable-row:hover {
  background: rgba(255, 255, 255, 0.04);
}

/* ── Leaderboard Panel ─────────────────────────────────────────────── */
.leaderboard-panel {
  margin-bottom: 16px;
  padding: 16px;
  background: var(--card-bg, #161b22);
  border: 1px solid var(--border-color, #30363d);
  border-radius: 8px;
}
.leaderboard-controls {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  margin-bottom: 16px;
  align-items: center;
}
.leaderboard-controls label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: #8b949e;
}
.leaderboard-controls select {
  background: #0d1117;
  color: #c9d1d9;
  border: 1px solid #30363d;
  border-radius: 6px;
  padding: 4px 8px;
  font-size: 13px;
}
.leaderboard-table-wrap {
  overflow-x: auto;
}
.leaderboard-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
.leaderboard-table th {
  text-align: left;
  padding: 8px 12px;
  color: #8b949e;
  font-weight: 600;
  border-bottom: 1px solid #30363d;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
}
.leaderboard-table th:hover {
  color: #c9d1d9;
}
.leaderboard-table th.sorted {
  color: #58a6ff;
}
.leaderboard-table td {
  padding: 8px 12px;
  border-bottom: 1px solid #21262d;
  color: #c9d1d9;
  white-space: nowrap;
}
.leaderboard-table tr:hover td {
  background: #1c2128;
}
.leaderboard-rank {
  font-weight: 700;
  font-size: 14px;
  min-width: 40px;
  text-align: center;
}
.rank-medal { font-size: 16px; }
.leaderboard-agent {
  font-weight: 600;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
}
.leaderboard-bar {
  display: inline-block;
  height: 8px;
  border-radius: 4px;
  background: #238636;
  vertical-align: middle;
  margin-left: 6px;
  transition: width 0.3s ease;
}
.leaderboard-bar.speed { background: #58a6ff; }
.leaderboard-bar.cost { background: #f0883e; }
.leaderboard-bar.volume { background: #8b5cf6; }
.leaderboard-empty {
  text-align: center;
  padding: 32px;
  color: #8b949e;
}
.leaderboard-stat-label {
  color: #8b949e;
  font-size: 11px;
}

